const _body = $json.body || $json; if (_body._smoke_test) return [{ json: { ok: true, smoke_test: true } }];
// ---- Pillar 5: RAG Searcher — natural language → pgvector → optional Groq synthesis ----
// Input: { query: '...', threshold?: 0.7, limit?: 5, synthesize?: true }
// 1) Embed query via Jina AI (same model as doc-ingester → cosine space matches)
// 2) Call Supabase RPC match_knowledge_base for top-k similar chunks
// 3) If synthesize=true: Groq 8b synthesizes an answer from the retrieved chunks
// Returns: { chunks: [...], answer?: '...' }
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const query = String(b.query || '').trim();
const threshold = parseFloat(b.threshold ?? 0.65);
const limit = Math.min(parseInt(b.limit ?? 5), 10);
const synthesize = b.synthesize !== false; // default true

if (!query) return [{ json: { ok: false, error: 'query is required' } }];
if (!ENV.JINA_API_KEY) return [{ json: { ok: false, error: 'JINA_API_KEY not set' } }];
if (!ENV.SUPABASE_URL) return [{ json: { ok: false, error: 'SUPABASE_URL not set' } }];

// Step 1: Embed query
let queryEmbedding;
try {
  const jinaRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.jina.ai/v1/embeddings',
    headers: { Authorization: `Bearer ${ENV.JINA_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'jina-embeddings-v2-base-en', input: [query] }),
    json: true, timeout: 20000
  });
  queryEmbedding = jinaRes.data[0].embedding;
} catch (e) { return [{ json: { ok: false, error: `Jina embed failed: ${e.message.slice(0,100)}` } }]; }

// Step 2: pgvector similarity search via Supabase RPC
let chunks = [];
try {
  const rpcRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/rpc/match_knowledge_base`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      query_embedding: queryEmbedding,
      match_threshold: threshold,
      match_count: limit
    }),
    json: true, timeout: 15000
  });
  chunks = Array.isArray(rpcRes) ? rpcRes : [];
} catch (e) { return [{ json: { ok: false, error: `Vector search failed: ${e.message.slice(0,100)}` } }]; }

if (!chunks.length) {
  return [{ json: { ok: true, query, chunks: [], answer: null, message: 'No matching documents found — try a lower threshold or ingest more content' } }];
}

// Step 3: Optional Groq synthesis
let answer = null;
if (synthesize && ENV.GROQ_API_KEY) {
  const context = chunks.map((c, i) => `[${i+1}] (${c.source || 'unknown'}) ${c.content}`).join('\n\n');
  try {
    const groqRes = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.groq.com/openai/v1/chat/completions',
      headers: { Authorization: `Bearer ${ENV.GROQ_API_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'llama-3.1-8b-instant',
        messages: [
          { role: 'system', content: 'You are a knowledge assistant for Markexis. Answer the user question using ONLY the provided context chunks. Be specific and cite sources. If the context doesn\'t contain enough information, say so clearly.' },
          { role: 'user', content: `Question: ${query}\n\nContext:\n${context}\n\nAnswer based on the context above:` }
        ],
        temperature: 0.2, max_tokens: 512
      }),
      json: true, timeout: 30000
    });
    answer = groqRes.choices[0].message.content;
  } catch { answer = null; }
}

return [{ json: {
  ok: true,
  query,
  chunks_found: chunks.length,
  chunks: chunks.map(c => ({ id: c.id, source: c.source, doc_type: c.doc_type, similarity: Math.round(c.similarity * 1000) / 1000, content: c.content })),
  answer,
  synthesized: !!answer
} }];
